create table if not exists knowledge_components (kc_id uuid not null, description varchar(255), kc_name varchar(255), primary key (kc_id));
create table if not exists lesson_kc_mapping (target_mastery bigint not null, kc_id uuid not null, lesson_id uuid not null, primary key (kc_id, lesson_id));
create table if not exists lessons (lesson_id uuid not null, module_id uuid, description varchar(255), lesson_name varchar(255), primary key (lesson_id));
create table if not exists modules (module_id uuid not null, description varchar(255), module_name varchar(255), primary key (module_id));
create table if not exists multiple_choice_questions (question_id uuid not null, correct_option_key varchar(255), options jsonb, primary key (question_id));
create table if not exists question_kc_mapping (weight float(53) not null, kc_id uuid not null, question_id uuid not null, primary key (kc_id, question_id));
create table if not exists questions (question_id uuid not null, question_type varchar(31) not null, hint_level_1 varchar(255), hint_level_2 varchar(255), question_text varchar(255), primary key (question_id));
create table if not exists scaffolds (order_index integer not null, question_id uuid not null, scaffold_id uuid not null, scaffold_correct_answer varchar(255), scaffold_text varchar(255), primary key (scaffold_id));
create table if not exists session (created_at timestamp(6) with time zone not null, end_time timestamp(6) with time zone, start_time timestamp(6) with time zone, updated_at timestamp(6) with time zone, session_id uuid not null, user_id uuid, device_type varchar(255), user_agent varchar(255), primary key (session_id));
create table if not exists student_interactions (hint_level integer not null, is_correct boolean not null, p_mastery float(53) not null, time_spent_seconds integer not null, timestamp timestamp(6) with time zone, interaction_id uuid not null, kc_id uuid, lesson_id uuid, question_id uuid, scaffold_id uuid, session_id uuid, user_id uuid, interaction_type varchar(255) check (interaction_type in ('LESSON_START','LESSON_EXIT','START_TEST','TEST_EXIT','QUIZ_ANSWER','HINT_REQUEST','SCAFFOLD_ANSWER')), student_answer varchar(255), primary key (interaction_id));
create table if not exists studentkcmastery (p_guess float(53) not null, p_mastery float(53) not null, p_slip float(53) not null, p_transit float(53) not null, updated_at timestamp(6) with time zone, kc_id uuid not null, user_id uuid not null, primary key (kc_id, user_id));
create table if not exists users (created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, user_id uuid not null, email varchar(255), google_id varchar(255), image_url varchar(255), username varchar(255), primary key (user_id));
create table if not exists written_question_entity (question_id uuid not null, answer_explanation varchar(255), correct_answer_text varchar(255), primary key (question_id));
